sql:
SELECT COUNT(student_id) AS student_count, program_id
FROM student_programs
GROUP BY program_id;

SELECT date, description
FROM student_records
WHERE type = 'academic';

external_knowledge:
"shining brighter than the average star" refers to programs with average marks higher than the overall average marks of all students;
"programs" are educational courses or degrees;
"students" are individuals enrolled in these programs.

sql:
SELECT COUNT(student_id) AS unselected_students_count
FROM student_programs
WHERE selected = 0;

external_knowledge:
- 'Selected students' are those who have been chosen for a program (selected = 1);
- 'Average grade' is the mean grade of a student across all subjects;
- 'Average mark' is the mean mark of all students in a specific program;
- 'Program start date' is the date when the program began, and it must be after January 1, 2022.

sql:
SELECT student_id, grade
FROM student_grades
ORDER BY grade DESC;

external_knowledge:
- 'students in the hierarchy' refers to the hierarchical structure of students and their associated teachers;
- 'selected students' indicates students who have been chosen for the program;
- 'average grade' is the mean grade of all students in the program.

sql:
SELECT COUNT(student_id)
FROM students
WHERE marks > (SELECT AVG(marks) FROM students);

SELECT first_name, marks
FROM students
WHERE marks > (SELECT AVG(marks) FROM students);

external_knowledge:
- 'Top-performing students' refers to students ranked in the top 10 based on their average grades;
- 'Involved in multiple programs' means students are enrolled in more than one program;
- 'Taught by teachers with a large student base' means teachers have more than 5 students;
- 'Long addresses' refers to addresses longer than 20 characters.

- "Garden of academic excellence" refers to the educational programs;
- "Nurturing the top 3 scholars" refers to the top 3 students with the highest average grades in each program;
- "How many students are enrolled" refers to the number of students selected for each program.

- 'blossoms' refers to students;
- 'surpassed the threshold of 80' refers to grades higher than 80;
- 'guardians or cultivators of knowledge' refers to teachers with roles 'administrator' or 'teacher'.

- "blossomed in more than one field of study" refers to students who are enrolled in more than one subject;
- "left their mark in the records" refers to students who have at least one record in the `student_records` table;
- "richness of their academic diversity" refers to the total number of subjects a student is enrolled in.

